97: /**
98:  * The checkpoint coordinator coordinates the distributed snapshots of operators and state. It
99:  * triggers the checkpoint by sending the messages to the relevant tasks and collects the checkpoint
100:  * acknowledgements. It also collects and maintains the overview of the state handles reported by
101:  * the tasks that acknowledge the checkpoint.
102:  */
103: public class CheckpointCoordinator {
104: 
105:     private static final Logger LOG = LoggerFactory.getLogger(CheckpointCoordinator.class);
106: 
107:     /** The number of recent checkpoints whose IDs are remembered. */
108:     private static final int NUM_GHOST_CHECKPOINT_IDS = 16;
109: 
110:     // ------------------------------------------------------------------------
111: 
112:     /** Coordinator-wide lock to safeguard the checkpoint updates. */
113:     private final Object lock = new Object();
114: 
115:     /** The job whose checkpoint this coordinator coordinates. */
116:     private final JobID job;
117: 
118:     /** Default checkpoint properties. */
119:     private final CheckpointProperties checkpointProperties;
120: 
121:     /** The executor used for asynchronous calls, like potentially blocking I/O. */
122:     private final Executor executor;
123: 
124:     private final CheckpointsCleaner checkpointsCleaner;
125: 
126:     /** The operator coordinators that need to be checkpointed. */
127:     private final Collection<OperatorCoordinatorCheckpointContext> coordinatorsToCheckpoint;
128: 
129:     /** Map from checkpoint ID to the pending checkpoint. */
130:     @GuardedBy("lock")
131:     private final Map<Long, PendingCheckpoint> pendingCheckpoints;
132: 
133:     /**
134:      * Completed checkpoints. Implementations can be blocking. Make sure calls to methods accessing
135:      * this don't block the job manager actor and run asynchronously.
136:      */
137:     private final CompletedCheckpointStore completedCheckpointStore;
138: 
139:     /**
140:      * The root checkpoint state backend, which is responsible for initializing the checkpoint,
141:      * storing the metadata, and cleaning up the checkpoint.
142:      */
143:     private final CheckpointStorageCoordinatorView checkpointStorageView;
144: 
145:     /** A list of recent expired checkpoint IDs, to identify late messages (vs invalid ones). */
146:     private final ArrayDeque<Long> recentExpiredCheckpoints;
147: 
148:     /**
149:      * Checkpoint ID counter to ensure ascending IDs. In case of job manager failures, these need to
150:      * be ascending across job managers.
151:      */
152:     private final CheckpointIDCounter checkpointIdCounter;
153: 
154:     /**
155:      * The checkpoint interval when there is no source reporting isProcessingBacklog=true. Actual
156:      * trigger time may be affected by the max concurrent checkpoints, minimum-pause values and
157:      * checkpoint interval during backlog.
158:      */
159:     private final long baseInterval;
160: 
161:     /**
162:      * The checkpoint interval when any source reports isProcessingBacklog=true. Actual trigger time
163:      * may be affected by the max concurrent checkpoints and minimum-pause values.
164:      */
165:     private final long baseIntervalDuringBacklog;
166: 
167:     /** The max time (in ms) that a checkpoint may take. */
168:     private final long checkpointTimeout;
169: 
170:     /**
171:      * The min time(in ms) to delay after a checkpoint could be triggered. Allows to enforce minimum
172:      * processing time between checkpoint attempts
173:      */
174:     private final long minPauseBetweenCheckpoints;
175: 
176:     /**
177:      * The timer that handles the checkpoint timeouts and triggers periodic checkpoints. It must be
178:      * single-threaded. Eventually it will be replaced by main thread executor.
179:      */
180:     private final ScheduledExecutor timer;
181: 
182:     /** The master checkpoint hooks executed by this checkpoint coordinator. */
183:     private final HashMap<String, MasterTriggerRestoreHook<?>> masterHooks;
184: 
185:     private final boolean unalignedCheckpointsEnabled;
186: 
187:     private final long alignedCheckpointTimeout;
188: 
189:     /** Actor that receives status updates from the execution graph this coordinator works for. */
190:     private JobStatusListener jobStatusListener;
191: 
192:     /**
193:      * The current periodic trigger. Used to deduplicate concurrently scheduled checkpoints if any.
194:      */
195:     @GuardedBy("lock")
196:     private ScheduledTrigger currentPeriodicTrigger;
197: 
198:     /** A handle to the current periodic trigger, to cancel it when necessary. */
199:     @GuardedBy("lock")
200:     private ScheduledFuture<?> currentPeriodicTriggerFuture;
201: 
202:     /**
203:      * The timestamp (via {@link Clock#relativeTimeMillis()}) when the next checkpoint will be
204:      * triggered.
205:      *
206:      * <p>If it's value is {@link Long#MAX_VALUE}, it means there is not a next checkpoint
207:      * scheduled.
208:      */
209:     @GuardedBy("lock")
210:     private long nextCheckpointTriggeringRelativeTime;
211: 
212:     /**
213:      * The timestamp (via {@link Clock#relativeTimeMillis()}) when the last checkpoint completed.
214:      */
215:     private long lastCheckpointCompletionRelativeTime;
216: 
217:     /**
218:      * Flag whether a triggered checkpoint should immediately schedule the next checkpoint.
219:      * Non-volatile, because only accessed in synchronized scope
220:      */
221:     private boolean periodicScheduling;
222: 
223:     /** Flag marking the coordinator as shut down (not accepting any messages any more). */
224:     private volatile boolean shutdown;
225: 
226:     /** Optional tracker for checkpoint statistics. */
227:     private final CheckpointStatsTracker statsTracker;
228: 
229:     private final BiFunction<
230:                     Set<ExecutionJobVertex>,
231:                     Map<OperatorID, OperatorState>,
232:                     VertexFinishedStateChecker>
233:             vertexFinishedStateCheckerFactory;
234: 
235:     /** Id of checkpoint for which in-flight data should be ignored on recovery. */
236:     private final long checkpointIdOfIgnoredInFlightData;
237: 
238:     private final CheckpointFailureManager failureManager;
239: 
240:     private final Clock clock;
241: 
242:     private final boolean isExactlyOnceMode;
243: 
244:     /** Flag represents there is an in-flight trigger request. */
245:     private boolean isTriggering = false;
246: 
247:     private final CheckpointRequestDecider requestDecider;
248: 
249:     private final CheckpointPlanCalculator checkpointPlanCalculator;
250: 
251:     /** IDs of the source operators that are currently processing backlog. */
252:     @GuardedBy("lock")
253:     private final Set<OperatorID> backlogOperators = new HashSet<>();
254: 
255:     private boolean baseLocationsForCheckpointInitialized = false;
256: 
257:     private boolean forceFullSnapshot;
