261:     public CheckpointCoordinator(
262:             JobID job,
263:             CheckpointCoordinatorConfiguration chkConfig,
264:             Collection<OperatorCoordinatorCheckpointContext> coordinatorsToCheckpoint,
265:             CheckpointIDCounter checkpointIDCounter,
266:             CompletedCheckpointStore completedCheckpointStore,
267:             CheckpointStorage checkpointStorage,
268:             Executor executor,
269:             CheckpointsCleaner checkpointsCleaner,
270:             ScheduledExecutor timer,
271:             CheckpointFailureManager failureManager,
272:             CheckpointPlanCalculator checkpointPlanCalculator,
273:             CheckpointStatsTracker statsTracker) {
274: 
275:         this(
276:                 job,
277:                 chkConfig,
278:                 coordinatorsToCheckpoint,
279:                 checkpointIDCounter,
280:                 completedCheckpointStore,
281:                 checkpointStorage,
282:                 executor,
283:                 checkpointsCleaner,
284:                 timer,
285:                 failureManager,
286:                 checkpointPlanCalculator,
287:                 SystemClock.getInstance(),
288:                 statsTracker,
289:                 VertexFinishedStateChecker::new);
290:     }
291: 
292:     @VisibleForTesting
293:     public CheckpointCoordinator(
294:             JobID job,
295:             CheckpointCoordinatorConfiguration chkConfig,
296:             Collection<OperatorCoordinatorCheckpointContext> coordinatorsToCheckpoint,
297:             CheckpointIDCounter checkpointIDCounter,
298:             CompletedCheckpointStore completedCheckpointStore,
299:             CheckpointStorage checkpointStorage,
300:             Executor executor,
301:             CheckpointsCleaner checkpointsCleaner,
302:             ScheduledExecutor timer,
303:             CheckpointFailureManager failureManager,
304:             CheckpointPlanCalculator checkpointPlanCalculator,
305:             Clock clock,
306:             CheckpointStatsTracker statsTracker,
307:             BiFunction<
308:                             Set<ExecutionJobVertex>,
309:                             Map<OperatorID, OperatorState>,
310:                             VertexFinishedStateChecker>
311:                     vertexFinishedStateCheckerFactory) {
312: 
313:         // sanity checks
314:         checkNotNull(checkpointStorage);
315: 
316:         // max "in between duration" can be one year - this is to prevent numeric overflows
317:         long minPauseBetweenCheckpoints = chkConfig.getMinPauseBetweenCheckpoints();
318:         if (minPauseBetweenCheckpoints > 365L * 24 * 60 * 60 * 1_000) {
319:             minPauseBetweenCheckpoints = 365L * 24 * 60 * 60 * 1_000;
320:         }
321: 
322:         // it does not make sense to schedule checkpoints more often then the desired
323:         // time between checkpoints
324:         long baseInterval = chkConfig.getCheckpointInterval();
325:         if (baseInterval < minPauseBetweenCheckpoints) {
326:             baseInterval = minPauseBetweenCheckpoints;
327:         }
328: 
329:         this.job = checkNotNull(job);
330:         this.baseInterval = baseInterval;
331:         this.baseIntervalDuringBacklog = chkConfig.getCheckpointIntervalDuringBacklog();
332:         this.nextCheckpointTriggeringRelativeTime = Long.MAX_VALUE;
333:         this.checkpointTimeout = chkConfig.getCheckpointTimeout();
334:         this.minPauseBetweenCheckpoints = minPauseBetweenCheckpoints;
335:         this.coordinatorsToCheckpoint =
336:                 Collections.unmodifiableCollection(coordinatorsToCheckpoint);
337:         this.pendingCheckpoints = new LinkedHashMap<>();
338:         this.checkpointIdCounter = checkNotNull(checkpointIDCounter);
339:         this.completedCheckpointStore = checkNotNull(completedCheckpointStore);
340:         this.executor = checkNotNull(executor);
341:         this.checkpointsCleaner = checkNotNull(checkpointsCleaner);
342:         this.failureManager = checkNotNull(failureManager);
343:         this.checkpointPlanCalculator = checkNotNull(checkpointPlanCalculator);
344:         this.clock = checkNotNull(clock);
345:         this.isExactlyOnceMode = chkConfig.isExactlyOnce();
346:         this.unalignedCheckpointsEnabled = chkConfig.isUnalignedCheckpointsEnabled();
347:         this.alignedCheckpointTimeout = chkConfig.getAlignedCheckpointTimeout();
348:         this.checkpointIdOfIgnoredInFlightData = chkConfig.getCheckpointIdOfIgnoredInFlightData();
349: 
350:         this.recentExpiredCheckpoints = new ArrayDeque<>(NUM_GHOST_CHECKPOINT_IDS);
351:         this.masterHooks = new HashMap<>();
352: 
353:         this.timer = timer;
354: 
355:         this.checkpointProperties =
356:                 CheckpointProperties.forCheckpoint(chkConfig.getCheckpointRetentionPolicy());
357: 
358:         try {
359:             this.checkpointStorageView = checkpointStorage.createCheckpointStorage(job);
360: 
361:             if (isPeriodicCheckpointingConfigured()) {
362:                 checkpointStorageView.initializeBaseLocationsForCheckpoint();
363:                 baseLocationsForCheckpointInitialized = true;
364:             }
365:         } catch (IOException e) {
366:             throw new FlinkRuntimeException(
367:                     "Failed to create checkpoint storage at checkpoint coordinator side.", e);
368:         }
369: 
370:         try {
371:             // Make sure the checkpoint ID enumerator is running. Possibly
372:             // issues a blocking call to ZooKeeper.
373:             checkpointIDCounter.start();
374:         } catch (Throwable t) {
375:             throw new RuntimeException(
376:                     "Failed to start checkpoint ID counter: " + t.getMessage(), t);
377:         }
378:         this.requestDecider =
379:                 new CheckpointRequestDecider(
380:                         chkConfig.getMaxConcurrentCheckpoints(),
381:                         this::rescheduleTrigger,
382:                         this.clock,
383:                         this.minPauseBetweenCheckpoints,
384:                         this.pendingCheckpoints::size,
385:                         this.checkpointsCleaner::getNumberOfCheckpointsToClean);
386:         this.statsTracker = checkNotNull(statsTracker, "Statistic tracker can not be null");
387:         this.vertexFinishedStateCheckerFactory = checkNotNull(vertexFinishedStateCheckerFactory);
388:     }
389: 
390:     // --------------------------------------------------------------------------------------------
391:     //  Configuration
392:     // --------------------------------------------------------------------------------------------
393: 
394:     /**
395:      * Adds the given master hook to the checkpoint coordinator. This method does nothing, if the
396:      * checkpoint coordinator already contained a hook with the same ID (as defined via {@link
397:      * MasterTriggerRestoreHook#getIdentifier()}).
398:      *
399:      * @param hook The hook to add.
400:      * @return True, if the hook was added, false if the checkpoint coordinator already contained a
401:      *     hook with the same ID.
402:      */
403:     public boolean addMasterHook(MasterTriggerRestoreHook<?> hook) {
404:         checkNotNull(hook);
405: 
406:         final String id = hook.getIdentifier();
407:         checkArgument(!StringUtils.isNullOrWhitespaceOnly(id), "The hook has a null or empty id");
408: 
409:         synchronized (lock) {
410:             if (!masterHooks.containsKey(id)) {
411:                 masterHooks.put(id, hook);
412:                 return true;
413:             } else {
414:                 return false;
415:             }
416:         }
417:     }
418: 
419:     /** Gets the number of currently register master hooks. */
420:     public int getNumberOfRegisteredMasterHooks() {
421:         synchronized (lock) {
422:             return masterHooks.size();
423:         }
424:     }
425: 
426:     // --------------------------------------------------------------------------------------------
427:     //  Clean shutdown
428:     // --------------------------------------------------------------------------------------------
429: 
430:     /**
431:      * Shuts down the checkpoint coordinator.
432:      *
433:      * <p>After this method has been called, the coordinator does not accept and further messages
434:      * and cannot trigger any further checkpoints.
435:      */
436:     public void shutdown() throws Exception {
437:         synchronized (lock) {
438:             if (!shutdown) {
439:                 shutdown = true;
440:                 LOG.info("Stopping checkpoint coordinator for job {}.", job);
441: 
442:                 periodicScheduling = false;
443: 
444:                 // shut down the hooks
445:                 MasterHooks.close(masterHooks.values(), LOG);
446:                 masterHooks.clear();
447: 
448:                 final CheckpointException reason =
449:                         new CheckpointException(
450:                                 CheckpointFailureReason.CHECKPOINT_COORDINATOR_SHUTDOWN);
451:                 // clear queued requests and in-flight checkpoints
452:                 abortPendingAndQueuedCheckpoints(reason);
453:             }
454:         }
455:     }
456: 
457:     public boolean isShutdown() {
458:         return shutdown;
459:     }
460: 
461:     /**
462:      * Reports whether a source operator is currently processing backlog.
463:      *
464:      * <p>If any source operator is processing backlog, the checkpoint interval would be decided by
465:      * {@code execution.checkpointing.interval-during-backlog} instead of {@code
466:      * execution.checkpointing.interval}.
467:      *
468:      * <p>If a source has not invoked this method, the source is considered to have
469:      * isProcessingBacklog=false. If a source operator has invoked this method multiple times, the
470:      * last reported value is used.
471:      *
472:      * @param operatorID the operator ID of the source operator.
473:      * @param isProcessingBacklog whether the source operator is processing backlog.
474:      */
475:     public void setIsProcessingBacklog(OperatorID operatorID, boolean isProcessingBacklog) {
476:         synchronized (lock) {
477:             if (isProcessingBacklog) {
478:                 backlogOperators.add(operatorID);
479:             } else {
480:                 backlogOperators.remove(operatorID);
481:             }
482: 
483:             long currentCheckpointInterval = getCurrentCheckpointInterval();
484:             if (currentCheckpointInterval
485:                     != CheckpointCoordinatorConfiguration.DISABLED_CHECKPOINT_INTERVAL) {
486:                 long currentRelativeTime = clock.relativeTimeMillis();
487:                 if (currentRelativeTime + currentCheckpointInterval
488:                         < nextCheckpointTriggeringRelativeTime) {
489:                     rescheduleTrigger(currentRelativeTime, currentCheckpointInterval);
490:                 }
491:             }
492:         }
493:     }
