1129:     public void receiveDeclineMessage(DeclineCheckpoint message, String taskManagerLocationInfo) {
1130:         if (shutdown || message == null) {
1131:             return;
1132:         }
1133: 
1134:         if (!job.equals(message.getJob())) {
1135:             throw new IllegalArgumentException(
1136:                     "Received DeclineCheckpoint message for job "
1137:                             + message.getJob()
1138:                             + " from "
1139:                             + taskManagerLocationInfo
1140:                             + " while this coordinator handles job "
1141:                             + job);
1142:         }
1143: 
1144:         final long checkpointId = message.getCheckpointId();
1145:         final CheckpointException checkpointException =
1146:                 message.getSerializedCheckpointException().unwrap();
1147:         final String reason = checkpointException.getMessage();
1148: 
1149:         PendingCheckpoint checkpoint;
1150: 
1151:         synchronized (lock) {
1152:             // we need to check inside the lock for being shutdown as well, otherwise we
1153:             // get races and invalid error log messages
1154:             if (shutdown) {
1155:                 return;
1156:             }
1157: 
1158:             checkpoint = pendingCheckpoints.get(checkpointId);
1159: 
1160:             if (checkpoint != null) {
1161:                 Preconditions.checkState(
1162:                         !checkpoint.isDisposed(),
1163:                         "Received message for discarded but non-removed checkpoint "
1164:                                 + checkpointId);
1165:                 LOG.info(
1166:                         "Decline checkpoint {} by task {} of job {} at {}.",
1167:                         checkpointId,
1168:                         message.getTaskExecutionId(),
1169:                         job,
1170:                         taskManagerLocationInfo,
1171:                         checkpointException.getCause());
1172:                 abortPendingCheckpoint(
1173:                         checkpoint, checkpointException, message.getTaskExecutionId());
1174:             } else if (LOG.isDebugEnabled()) {
1175:                 if (recentExpiredCheckpoints.contains(checkpointId)) {
1176:                     // message is for an expired checkpoint
1177:                     LOG.debug(
1178:                             "Received another decline message for now expired checkpoint attempt {} from task {} of job {} at {} : {}",
1179:                             checkpointId,
1180:                             message.getTaskExecutionId(),
1181:                             job,
1182:                             taskManagerLocationInfo,
1183:                             reason);
1184:                 } else {
1185:                     // message is for an unknown checkpoint. might be so old that we don't even
1186:                     // remember it any more
1187:                     LOG.debug(
1188:                             "Received decline message for unknown (too old?) checkpoint attempt {} from task {} of job {} at {} : {}",
1189:                             checkpointId,
1190:                             message.getTaskExecutionId(),
1191:                             job,
1192:                             taskManagerLocationInfo,
1193:                             reason);
