154: 
155:                 // make sure we do not track too many checkpoints
156:                 if (pendingCheckpoints.size() > MAX_CHECKPOINTS_TO_TRACK) {
157:                     pendingCheckpoints.pollFirst();
158:                 }
159:             }
160:         }
161:     }
