1433:     private boolean performCheckpoint(
1434:             CheckpointMetaData checkpointMetaData,
1435:             CheckpointOptions checkpointOptions,
1436:             CheckpointMetricsBuilder checkpointMetrics)
1437:             throws Exception {
1438: 
1439:         final SnapshotType checkpointType = checkpointOptions.getCheckpointType();
1440:         LOG.debug(
1441:                 "Starting checkpoint {} {} on task {}",
1442:                 checkpointMetaData.getCheckpointId(),
1443:                 checkpointType,
1444:                 getName());
1445: 
1446:         if (isRunning) {
1447:             actionExecutor.runThrowing(
1448:                     () -> {
1449:                         if (isSynchronous(checkpointType)) {
1450:                             setSynchronousSavepoint(checkpointMetaData.getCheckpointId());
1451:                         }
1452: 
1453:                         if (areCheckpointsWithFinishedTasksEnabled()
1454:                                 && endOfDataReceived
