1461:                                 checkpointOptions,
1462:                                 checkpointMetrics,
1463:                                 operatorChain,
1464:                                 finishedOperators,
1465:                                 this::isRunning);
1466:                     });
1467: 
1468:             return true;
1469:         } else {
