1088:     private CompletableFuture<Acknowledge> triggerCheckpointHelper(
1089:             long checkpointId, long timestamp, CheckpointOptions checkpointOptions) {
1090: 
1091:         final LogicalSlot slot = assignedResource;
1092: 
1093:         if (slot != null) {
1094:             final TaskManagerGateway taskManagerGateway = slot.getTaskManagerGateway();
1095: 
1096:             return taskManagerGateway.triggerCheckpoint(
1097:                     attemptId, getVertex().getJobId(), checkpointId, timestamp, checkpointOptions);
1098:         }
1099:         LOG.debug(
1100:                 "The execution has no slot assigned. This indicates that the execution is no longer running.");
1101:         return CompletableFuture.completedFuture(Acknowledge.get());
1102:     }
