1108:      */
1109:     public CompletableFuture<Acknowledge> sendOperatorEvent(
1110:             OperatorID operatorId, SerializedValue<OperatorEvent> event) {
1111: 
1112:         assertRunningInJobMasterMainThread();
1113:         final LogicalSlot slot = assignedResource;
1114: 
