367:     @Nullable
368:     private CompletedCheckpointStats toCompletedCheckpointStats(
369:             CompletedCheckpointStorageLocation finalizedLocation) {
370:         return pendingCheckpointStats != null
371:                 ? pendingCheckpointStats.toCompletedCheckpointStats(
372:                         finalizedLocation.getExternalPointer(),
373:                         finalizedLocation.getMetadataHandle().getStateSize())
374:                 : null;
375:     }
